// Reference code first, amount as secondary guard -- never amount
// alone. Both sides normalized (whitespace stripped, uppercased)
// before comparison so human formatting variance doesn't cause a
// silent match failure (B1).

const fs = require('fs');
const path = require('path');

function normalize(s) { return String(s || '').replace(/\s+/g, '').toUpperCase(); }

const bodyText = normalize($json.text || $json.html || '');
const refMatch = bodyText.match(/CIRCLEOFCARE-[A-Z0-9]+/);
const amountMatch = ($json.text || '').match(/\$[\d,]+(?:\.\d{2})?/);

if (!refMatch) return [{ json: { matched: false, reason: 'no_reference_code_found' } }];

let pending = [];
try { pending = JSON.parse(fs.readFileSync(path.join('Shared', 'intake_log.json'), 'utf8')); } catch (e) {}

const candidate = pending.find(p => normalize(p.reference_code) === refMatch[0] && p.status === 'order_confirmed');
if (!candidate) return [{ json: { matched: false, reason: 'no_pending_order_for_reference' } }];

// Amount as guard, not primary
if (amountMatch) {
  const paidAmount = amountMatch[0].replace(/[$,]/g, '');
  if (parseFloat(paidAmount).toFixed(2) !== parseFloat(candidate.amount).toFixed(2)) {
    return [{ json: { matched: false, reason: 'amount_mismatch_guard_failed', reference: refMatch[0] } }];
  }
}

// Skip already-active/pending codes to prevent duplicate token runs.
if (candidate.status === 'payment_confirmed') {
  return [{ json: { matched: false, reason: 'already_processed' } }];
}

return [{ json: { matched: true, reference_code: refMatch[0], project_prefix: candidate.project_prefix, contact_hash: candidate.contact_hash } }];

const fs = require('fs');
const path = require('path');
let pending = JSON.parse(fs.readFileSync(path.join('Shared', 'intake_log.json'), 'utf8'));
pending = pending.map(p => p.reference_code === $json.reference_code ? { ...p, status: 'payment_confirmed', payment_confirmed_at: new Date().toISOString() } : p);
fs.writeFileSync(path.join('Shared', 'intake_log.json'), JSON.stringify(pending, null, 2), 'utf8');
return [{ json: $json }];

// Scans for abuse/FBL notifications -- separate from payment matching
// on the same inbox poll (A7).
const text = ($json.text || '') + ' ' + ($json.subject || '');
if (/abuse report|feedback loop|spam complaint/i.test(text)) {
  const fs = require('fs');
  const path = require('path');
  const emailMatch = text.match(/[^\s@]+@[^\s@]+\.[^\s@]+/);
  if (emailMatch) {
    const crypto = require('crypto');
    const hash = crypto.createHash('sha256').update(emailMatch[0].toLowerCase().trim().replace(/\+.*@/, '@')).digest('hex');
    let dnc = [];
    try { dnc = fs.readFileSync(path.join('Shared', 'global_dnc.txt'), 'utf8').split('\n').filter(Boolean); } catch (e) {}
    if (!dnc.includes(hash)) fs.appendFileSync(path.join('Shared', 'global_dnc.txt'), hash + '\n', 'utf8');
  }
}
return [{ json: $json }];
